#include<bits/stdc++.h>
using namespace std;
int a[4040][4040],dp[4040][4040];
int main()
{
    int n,m,k,t;
    scanf("%d%d%d%d",&n,&m,&k,&t);
    for(int i=1;i<=k;i++)
    {
        int x,y,v;
        scanf("%d%d%d",&x,&y,&v);
        a[x][y]=v;
    }
    for(int i=1;i<=n;i++)
    {
        deque<int> q;
        for(int j=1;j<=m;j++)
        {
            while(!q.empty()&&dp[i-1][q.back()]<=dp[i-1][j])
            {
                q.pop_back();
            }
            q.push_back(j);
            while(!q.empty()&&q.front()<j-t)
            {
                q.pop_front();
            }
            dp[i][j]=dp[i-1][q.front()]+a[i][j];
        }
        for(int j=m;j>=1;j--)
        {
            while(!q.empty()&&dp[i-1][q.back()]<=dp[i-1][j])
            {
                q.pop_back();
            }
            q.push_back(j);
            while(!q.empty()&&q.front()>j+t)
            {
                q.pop_front();
            }
            dp[i][j]=max(dp[i][j],dp[i-1][q.front()]+a[i][j]);
        }
    }
    int ans=0;
    for(int i=1;i<=m;i++)
    {
        ans=max(ans,dp[n][i]);
    }
    printf("%d",ans);
    return 0;
}
